SELECT , u.name AS manager_name FROM tb_project p LEFT JOIN tb_user u ON p.manager_id = u.id WHERE p.is_deleted = 0
AND (p.name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY p.create_time DESC LIMIT #{offset}, #{size}

mapper.update:
UPDATE tb_project
name = #{name}, description = #{description}, manager_id = #{managerId}, start_date = #{startDate}, end_date = #{endDate}, status = #{status},
WHERE id = #{id}
